SELECT ?sourceLabel ?mouthLabel WHERE {
  wd:Q415338 wdt:P185 ?source .
  wd:Q415338 wdt:P132 ?mouth .
  OPTIONAL {
    ?source rdfs:label ?sourceLabel .
    FILTER(LANG(?sourceLabel) = 'en')
  }
  OPTIONAL {
    ?mouth rdfs:label ?mouthLabel .
    FILTER(LANG(?mouthLabel) = 'en')
  }
}

SELECT ?person ?name WHERE {
  ?person wdt:P106 wd:Q161453 .
  ?person wdt:P569 ?birthDate .
  FILTER NOT EXISTS {
